const results = [];

for (const item of items) {
  const {
    product_id,
    sku,
    product_name,
    stock_quantity,
    avg_daily_demand,
    manage_stock
  } = item.json;

  // ADD THIS BLOCK (TOP of loop)
  if (!manage_stock) {
    results.push({
      json: {
        product_id,
        sku,
        product_name,
        stock_quantity,
        avg_daily_demand,
        days_of_stock_left: null,
        inventory_status: 'Not Managed',
        reorder_needed: false,
        recommended_action: 'Stock not managed'
      }
    });
    continue;
  }
  // END ADDITION

  let days_of_stock_left = null;
  let inventory_status = '';
  let reorder_needed = false;
  let recommended_action = '';

  if (avg_daily_demand > 0) {
    days_of_stock_left = stock_quantity / avg_daily_demand;
  }

  if (avg_daily_demand === 0 && stock_quantity > 0) {
    inventory_status = 'Consider Discontinue';
    recommended_action = 'Stop restocking / apply discount';
  } else if (days_of_stock_left < 15) {
    inventory_status = 'At Risk';
    reorder_needed = true;
    recommended_action = 'Reorder immediately';
  } else if (days_of_stock_left <= 45) {
    inventory_status = 'Steady';
    recommended_action = 'Monitor stock';
  } else {
    inventory_status = 'Top Performer';
    recommended_action = 'Maintain stock level';
  }

  results.push({
    json: {
      product_id,
      sku,
      product_name,
      stock_quantity,
      avg_daily_demand,
      days_of_stock_left,
      inventory_status,
      reorder_needed,
      recommended_action
    }
  });
}

return results;

const productSales = {};

// Dates
const now = new Date();
const thirtyDaysAgo = new Date();
thirtyDaysAgo.setDate(now.getDate() - 30);

// Loop through orders
for (const item of items) {
  const order = item.json;

  const date_completed = order.date_completed
    ? new Date(order.date_completed)
    : null;

  if (!date_completed || date_completed < thirtyDaysAgo) continue;

  for (const li of order.line_items || []) {
    const product_id = li.product_id;
    const qty = li.quantity || 0;

    if (!productSales[product_id]) {
      productSales[product_id] = {
        product_id,
        units_sold_last_30_days: 0
      };
    }

    productSales[product_id].units_sold_last_30_days += qty;
  }
}

// Final output
return Object.values(productSales).map(p => ({
  json: {
    product_id: p.product_id,
    units_sold_last_30_days: p.units_sold_last_30_days,
    avg_daily_demand: p.units_sold_last_30_days / 30
  }
}));

const products = [];
const salesMap = {};

// Separate inputs
for (const item of items) {
  // Product data
  if (item.json.stock_quantity !== undefined && item.json.id) {
    products.push(item.json);
  }

  // Sales data
  if (item.json.product_id !== undefined) {
    salesMap[item.json.product_id] = item.json;
  }
}

const result = [];

for (const product of products) {
  const sales = salesMap[product.id] || {
    units_sold_last_30_days: 0,
    avg_daily_demand: 0
  };

  result.push({
    json: {
      product_id: product.id,
      sku: product.sku,
      product_name: product.name,
      stock_quantity: product.stock_quantity,
      manage_stock: product.manage_stock,

      units_sold_last_30_days: sales.units_sold_last_30_days,
      avg_daily_demand: sales.avg_daily_demand
    }
  });
}

return result;

const LEAD_TIME_DAYS = 7;
const SAFETY_DAYS = 5;

return items.map(item => {
  const d = item.json; 

  const dailyDemand = Math.max(d.avg_daily_demand || 0, 0.01);

  const safety_stock =
    dailyDemand * SAFETY_DAYS;

  const reorder_point =
    (dailyDemand * LEAD_TIME_DAYS) + safety_stock;

  const target_stock =
    dailyDemand * (LEAD_TIME_DAYS + SAFETY_DAYS);

  const reorder_qty_raw =
    Math.ceil(target_stock - d.stock_quantity);

  const reorder_qty =
    reorder_qty_raw > 0 ? reorder_qty_raw : 0;

  return {
    json: {
      ...d,
      safety_stock: Math.ceil(safety_stock),
      reorder_point: Math.ceil(reorder_point),
      target_stock: Math.ceil(target_stock),
      reorder_qty
    }
  };
});

return items.map(item => {
  const d = item.json;

  let urgency = "Normal";
  let action = d.recommended_action;

  if (d.reorder_qty > 0) {
    if (d.days_of_stock_left <= 7) {
      urgency = "Critical";
      action = `Order ${d.reorder_qty} units immediately`;
    } else if (d.days_of_stock_left <= 14) {
      urgency = "High";
      action = `Plan reorder of ${d.reorder_qty} units`;
    } else {
      urgency = "Normal";
      action = `Monitor – next reorder ${d.reorder_qty} units`;
    }
  }

  return {
    json: {
      ...d,
      urgency_level: urgency,
      final_recommended_action: action
    }
  };
});

