let totalProducts = 0;
let atRisk = 0;
let reorderNeeded = 0;

const lines = [];

for (const item of items) {
  const d = item.json;

  totalProducts++;

  // Count At Risk
  if (d["inventory status"] === "At Risk") {
    atRisk++;
  }

  // Reorder logic (based on status since reorder flag not stored)
  if (d["inventory status"] === "At Risk") {
    reorderNeeded++;
  }

  lines.push(
    `• ${d["product name"]} → ${d["inventory status"]} (Stock: ${d.quantity})`
  );
}

return [
  {
    json: {
      totalProducts,
      atRisk,
      reorderNeeded,
      summaryText: lines.join("\n")
    }
  }
];

